class Solution {
public:
    string originalDigits(string s) {
        int count[10] = {0};
        for (char c : s) {
            if (c == 'z') count[0]++;
            else if (c == 'w') count[2]++;
            else if (c == 'u') count[4]++;
            else if (c == 'x') count[6]++;
            else if (c == 'g') count[8]++;
            else if (c == 'f') count[5]++;
            else if (c == 'h') count[3]++;
            else if (c == 'i') count[9]++;
            else if (c == 'o') count[1]++;
            else if (c == 'n') count[7]++;
        }
        string result = "";
        for (int i = 0; i < 10; i++) {
            result += string(count[i], '0' + i);
        }
        return result;
    }
};
```
